import{V as e,et as t,mt as n,tt as r}from"./chunks/framework.Bb5YUzRP.js";var i=JSON.parse(`{"title":"Scaffolding","description":"Scaffold a new Nodalite project with npm create nodalite. Interactive CLI generates API servers, Lambda functions, Edge workers, or Telegram bots. ","frontmatter":{"description":"Scaffold a new Nodalite project with npm create nodalite. Interactive CLI generates API servers, Lambda functions, Edge workers, or Telegram bots. "},"headers":[],"relativePath":"guide/scaffolding.md","filePath":"guide/scaffolding.md","lastUpdated":1784063781000}`),a={name:`guide/scaffolding.md`};function o(e,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[r(`<h1 id="scaffolding" tabindex="-1">Scaffolding <a class="header-anchor" href="#scaffolding" aria-label="Permalink to “Scaffolding”">​</a></h1><p>Create a new Nodalite project in seconds with the interactive scaffolding CLI.</p><h2 id="quick-start" tabindex="-1">Quick start <a class="header-anchor" href="#quick-start" aria-label="Permalink to “Quick start”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodalite</span></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># or</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nodalite</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># or</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-nodalite</span></span></code></pre></div><p>Follow the prompts to configure your project — a ready-to-run project is generated with all dependencies installed.</p><h2 id="interactive-prompts" tabindex="-1">Interactive prompts <a class="header-anchor" href="#interactive-prompts" aria-label="Permalink to “Interactive prompts”">​</a></h2><h3 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to “Purpose”">​</a></h3><p>Choose the type of project you want to build:</p><table tabindex="0"><thead><tr><th>Option</th><th>Runtime</th><th>Generated files</th></tr></thead><tbody><tr><td><strong>API server</strong></td><td>Node.js / Bun / Deno</td><td><code>src/app.ts</code>, <code>src/server.ts</code>, <code>tsconfig.json</code></td></tr><tr><td><strong>Telegram bot</strong></td><td>Node.js</td><td><code>src/main.ts</code>, <code>src/telegram-bot.ts</code>, <code>tsconfig.json</code></td></tr><tr><td><strong>Lambda</strong></td><td>AWS Lambda</td><td><code>src/app.ts</code>, <code>src/handler.ts</code>, <code>tsconfig.json</code></td></tr><tr><td><strong>Edge</strong></td><td>Cloudflare Workers</td><td><code>src/index.ts</code>, <code>wrangler.toml</code> config</td></tr></tbody></table><h3 id="additional-options" tabindex="-1">Additional options <a class="header-anchor" href="#additional-options" aria-label="Permalink to “Additional options”">​</a></h3><p>After selecting the purpose, the CLI asks feature-specific questions:</p><p><strong>ML model inference</strong> (API only) — adds an ONNX-ready sentiment analysis endpoint powered by <code>@nodalite/workers</code> <code>WorkerPool</code>. The generated worker file (<code>src/sentiment-worker.ts</code>) runs CPU-bound inference on a dedicated thread so it never blocks the request event loop.</p><p><strong>Security middleware</strong> (API and Lambda) — adds <code>cors</code>, <code>securityHeaders</code>, <code>rateLimit</code>, <code>jwtAuth</code>, <code>logger</code>, and <code>bodyLimit</code> middleware. Auth routes (<code>/auth/signup</code>, <code>/auth/login</code>) and a JWT-protected <code>/api/*</code> group are generated with working validation via Zod.</p><p><strong>Job scheduler</strong> (API only) — adds a <code>@nodalite/scheduler</code> <code>Scheduler</code> instance with a sample recurring task and graceful shutdown wiring.</p><h3 id="structure" tabindex="-1">Structure <a class="header-anchor" href="#structure" aria-label="Permalink to “Structure”">​</a></h3><p>Choose how your source code is organized:</p><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td><strong>Flat</strong> (default)</td><td>All routes in a single <code>src/app.ts</code> file</td></tr><tr><td><strong>Modular</strong></td><td>Routes split into <code>src/routes/</code> with <a href="/api/core#discover">auto-discovery</a></td></tr></tbody></table><p>The modular structure automatically discovers route files from the <code>routes/</code> directory using <code>discover()</code>. Subdirectories become route groups, and <code>_prefix.ts</code> files define prefixes for their directory.</p><h3 id="project-name" tabindex="-1">Project name <a class="header-anchor" href="#project-name" aria-label="Permalink to “Project name”">​</a></h3><p>If not provided as a CLI argument, the CLI prompts for a project name and creates a directory with that name in the current working directory.</p><h2 id="generated-project-structure" tabindex="-1">Generated project structure <a class="header-anchor" href="#generated-project-structure" aria-label="Permalink to “Generated project structure”">​</a></h2><p>The output mirrors the <a href="/examples/basic-api">examples</a> in the repository, customised to your choices. Here is what a full-featured API project with all options enabled looks like:</p><h3 id="flat-structure-default" tabindex="-1">Flat structure (default) <a class="header-anchor" href="#flat-structure-default" aria-label="Permalink to “Flat structure (default)”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>my-api/</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── app.ts                # Routes, middleware, ML worker pool</span></span>
<span class="line"><span>│   ├── server.ts             # HTTP server + graceful shutdown</span></span>
<span class="line"><span>│   └── sentiment-worker.ts   # ML inference worker thread</span></span>
<span class="line"><span>├── package.json              # Dependencies pinned to compatible versions</span></span>
<span class="line"><span>└── tsconfig.json             # Strict TypeScript config</span></span></code></pre></div><h3 id="modular-structure" tabindex="-1">Modular structure <a class="header-anchor" href="#modular-structure" aria-label="Permalink to “Modular structure”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>my-api/</span></span>
<span class="line"><span>├── src/</span></span>
<span class="line"><span>│   ├── app.ts                # Entry point with middleware + discover()</span></span>
<span class="line"><span>│   ├── server.ts             # HTTP server + graceful shutdown</span></span>
<span class="line"><span>│   └── routes/</span></span>
<span class="line"><span>│       ├── _prefix.ts        # Optional: defines &quot;/api&quot; prefix</span></span>
<span class="line"><span>│       ├── health.ts         # GET /health</span></span>
<span class="line"><span>│       ├── users.ts          # GET/POST /users</span></span>
<span class="line"><span>│       └── posts/</span></span>
<span class="line"><span>│           ├── _prefix.ts    # defines &quot;/posts&quot; prefix</span></span>
<span class="line"><span>│           ├── index.ts      # GET /posts</span></span>
<span class="line"><span>│           └── comments.ts   # GET /posts/comments</span></span>
<span class="line"><span>├── package.json</span></span>
<span class="line"><span>└── tsconfig.json</span></span></code></pre></div><h2 id="installing-dependencies" tabindex="-1">Installing dependencies <a class="header-anchor" href="#installing-dependencies" aria-label="Permalink to “Installing dependencies”">​</a></h2><p>After scaffolding, the CLI runs <code>npm install</code> automatically. If it fails (offline, custom registry, etc.), run it manually:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-project</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h2 id="what-s-next" tabindex="-1">What&#39;s next? <a class="header-anchor" href="#what-s-next" aria-label="Permalink to “What&#39;s next?”">​</a></h2><ul><li><a href="/guide/quickstart">Quick Start</a> — learn the framework basics</li><li><a href="/guide/core-concepts">Core Concepts</a> — how the request pipeline works</li><li><a href="/examples/basic-api">Examples</a> — real-world usage patterns</li></ul>`,31)]])}var s=e(a,[[`render`,o]]);export{i as __pageData,s as default};